mapper.select:
select p.id, o.order_code, bm.nickname as buyer_name, sm.nickname as seller_name, o.order_type, w.title as work_title, p.total_price, to_char(p.paid_at, 'MM.DD') as paid_at, p.status from tbl_payment p join tbl_order o on p.order_code = o.order_code join tbl_member bm on p.buyer_id = bm.id join tbl_member sm on p.seller_id = sm.id left join tbl_work w on p.work_id = w.id
and ( o.order_code ilike '%' || #{keyword} || '%' or bm.nickname ilike '%' || #{keyword} || '%' or w.title ilike '%' || #{keyword} || '%' )
and p.status = #{status}
order by p.id desc limit #{size} offset #{offset}

select count(*) from tbl_payment p join tbl_order o on p.order_code = o.order_code join tbl_member bm on p.buyer_id = bm.id join tbl_member sm on p.seller_id = sm.id left join tbl_work w on p.work_id = w.id
and ( o.order_code ilike '%' || #{keyword} || '%' or bm.nickname ilike '%' || #{keyword} || '%' or w.title ilike '%' || #{keyword} || '%' )
and p.status = #{status}
